class SessionWindowTracker:
    """
    Tracks user sessions. A session closes if no event arrives
    within `timeout_seconds` of the last event for that user.
    """

    def __init__(self, timeout_seconds: int = 30):
        self.timeout = timeout_seconds
        # user_id -> {"start": float, "last": float, "events": int}
        self.sessions: dict[str, dict] = {}

    def process(self, event: dict) -> list[dict]:
        """Process event and return any closed sessions."""
        now = event.get("timestamp", time.time())
        user_id = event["user_id"]
        closed_sessions = []

        # Close expired sessions for other users
        for uid, session in list(self.sessions.items()):
            if uid != user_id and (now - session["last"]) > self.timeout:
                closed_sessions.append({
                    "user_id": uid,
                    "session_start": session["start"],
                    "session_end": session["last"],
                    "duration": session["last"] - session["start"],
                    "event_count": session["events"]
                })
                del self.sessions[uid]

        # Update or create session for current user
        if user_id in self.sessions:
            if (now - self.sessions[user_id]["last"]) > self.timeout:
                # This event starts a new session
                closed_sessions.append({
                    "user_id": user_id,
                    "session_start": self.sessions[user_id]["start"],
                    "session_end": self.sessions[user_id]["last"],
                    "duration": self.sessions[user_id]["last"] - self.sessions[user_id]["start"],
                    "event_count": self.sessions[user_id]["events"]
                })
                self.sessions[user_id] = {"start": now, "last": now, "events": 1}
            else:
                self.sessions[user_id]["last"] = now
                self.sessions[user_id]["events"] += 1
        else:
            self.sessions[user_id] = {"start": now, "last": now, "events": 1}

        return closed_sessions

